using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 breaking change: HasIndex() now throws on Cosmos (was silently ignored).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);

        // EF9 breaking change: Discriminator property renamed from "Discriminator" to "$type".
        // Preserve old property name for compatibility with existing documents.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF9 breaking change: Id format changed from "{Discriminator}|{Key}" to just "{Key}".
        // Preserve old id format for compatibility with existing documents.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<LegacyCosmosIdGenerator>();
    }
}

// Generates ids in the legacy "Discriminator|Key" format used by EF Core 8.
class LegacyCosmosIdGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
        => $"Blog|{Guid.NewGuid()}";
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

